+                keys: vec![b"queue".to_vec()],
+            },
+            deadline_ms: 20,
+        });
+        blocked_conn.read_buf.extend_from_slice(
+            &RespFrame::Array(Some(vec![
+                RespFrame::BulkString(Some(b"GET".to_vec())),
